-- ----------------------------
-- Table structure for base_goods
-- ----------------------------
DROP TABLE IF EXISTS `base_goods`;
CREATE TABLE `base_goods` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `goods_no` varchar(50) NOT NULL COMMENT '货物编号',
  `name` varchar(100) NOT NULL COMMENT '货物名称',
  `type_id` bigint NOT NULL COMMENT '货物类型ID',
  `image_url` varchar(255) DEFAULT NULL COMMENT '图片URL',
  `unit` varchar(20) DEFAULT '件' COMMENT '单位',
  `weight` decimal(10,2) DEFAULT NULL COMMENT '重量(kg)',
  `volume` decimal(10,4) DEFAULT NULL COMMENT '体积(m³)',
  `value` decimal(12,2) DEFAULT NULL COMMENT '价值(元)',
  `manufacturer` varchar(100) DEFAULT NULL COMMENT '生产厂家',
  `specifications` varchar(255) DEFAULT NULL COMMENT '规格型号',
  `description` text COMMENT '描述',
  `is_deleted` tinyint DEFAULT '0' COMMENT '是否删除',
  `created_by` bigint DEFAULT NULL COMMENT '创建人ID',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `stock` int DEFAULT '0' COMMENT '库存数量',
  PRIMARY KEY (`id`),
  UNIQUE KEY `goods_no` (`goods_no`),
  KEY `fk_goods_type` (`type_id`),
  CONSTRAINT `fk_goods_type` FOREIGN KEY (`type_id`) REFERENCES `base_goods_types` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=51 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='货物基础信息表：存储货物核心信息（名称、规格、重量等），是货物相关业务基础';

-- ----------------------------
-- Records of base_goods
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for base_goods_types
-- ----------------------------
DROP TABLE IF EXISTS `base_goods_types`;
CREATE TABLE `base_goods_types` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `type_name` varchar(50) NOT NULL COMMENT '类型名称',
  `sort_order` int DEFAULT '0' COMMENT '排序',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='货物类型基础表：存储货物分类数据（如易碎品、电子产品），用于货物归类';

-- ----------------------------
-- Records of base_goods_types
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for biz_detections
-- ----------------------------
DROP TABLE IF EXISTS `biz_detections`;
CREATE TABLE `biz_detections` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `detection_no` varchar(50) NOT NULL COMMENT '检测编号',
  `transport_id` bigint NOT NULL COMMENT '运输ID',
  `operator_id` bigint DEFAULT NULL COMMENT '操作员ID',
  `image_url` varchar(255) DEFAULT NULL COMMENT '原图',
  `processed_image_url` varchar(255) DEFAULT NULL COMMENT '处理图',
  `detection_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '检测时间',
  `damage_level` tinyint DEFAULT '0' COMMENT '破损等级',
  `damage_area` decimal(5,2) DEFAULT '0.00' COMMENT '破损面积%',
  `confidence` decimal(5,4) DEFAULT NULL COMMENT '置信度',
  `damage_type` varchar(50) DEFAULT NULL COMMENT '破损类型',
  `damage_description` text COMMENT '描述',
  `suggestion` text COMMENT '建议',
  `status` tinyint DEFAULT '1' COMMENT '状态',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `detection_no` (`detection_no`),
  KEY `fk_detection_transport` (`transport_id`),
  CONSTRAINT `fk_detection_transport` FOREIGN KEY (`transport_id`) REFERENCES `biz_transports` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=55 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='破损检测业务表：存储货物破损检测记录（检测结果、破损程度等），对应检测记录管理模块';

-- ----------------------------
-- Records of biz_detections
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for biz_transports
-- ----------------------------
DROP TABLE IF EXISTS `biz_transports`;
CREATE TABLE `biz_transports` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `transport_no` varchar(50) NOT NULL COMMENT '运输单号',
  `goods_id` bigint NOT NULL COMMENT '货物ID',
  `quantity` int NOT NULL DEFAULT '1' COMMENT '数量',
  `origin` varchar(100) DEFAULT NULL COMMENT '发货地',
  `destination` varchar(100) DEFAULT NULL COMMENT '目的地',
  `carrier` varchar(100) DEFAULT NULL COMMENT '承运商',
  `vehicle_no` varchar(50) DEFAULT NULL COMMENT '车牌号',
  `driver_name` varchar(50) DEFAULT NULL COMMENT '司机姓名',
  `driver_phone` varchar(20) DEFAULT NULL COMMENT '司机电话',
  `start_time` datetime DEFAULT NULL COMMENT '开始时间',
  `end_time` datetime DEFAULT NULL COMMENT '结束时间',
  `status` tinyint DEFAULT '0' COMMENT '状态: 0-待运输, 1-运输中, 2-已完成, 3-异常, 4-已取消',
  `remarks` text COMMENT '备注',
  `is_deleted` tinyint DEFAULT '0' COMMENT '是否删除',
  `created_by` bigint DEFAULT NULL COMMENT '创建人ID',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `customer_name` varchar(100) DEFAULT NULL COMMENT '客户名称/收货人',
  PRIMARY KEY (`id`),
  UNIQUE KEY `transport_no` (`transport_no`),
  KEY `fk_transport_goods` (`goods_id`),
  CONSTRAINT `fk_transport_goods` FOREIGN KEY (`goods_id`) REFERENCES `base_goods` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=51 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='运输业务表：存储货物运输信息（起始地、目的地、运输状态等），对应运输记录管理模块';

-- ----------------------------
-- Records of biz_transports
-- ----------------------------
BEGIN;
COMMIT;

