-- ----------------------------
-- Table structure for sys_users
-- ----------------------------
DROP TABLE IF EXISTS `sys_users`;
CREATE TABLE `sys_users` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '用户唯一 ID',
  `username` varchar(50) NOT NULL COMMENT '登录账号',
  `password` varchar(100) NOT NULL COMMENT '密码',
  `name` varchar(50) DEFAULT NULL COMMENT '用户真实姓名',
  `avatar` varchar(255) DEFAULT NULL COMMENT '头像 URL',
  `email` varchar(100) DEFAULT NULL COMMENT '邮箱',
  `phone` varchar(20) DEFAULT NULL COMMENT '手机号',
  `status` tinyint DEFAULT '1' COMMENT '状态（1 - 启用，0 - 禁用）',
  `last_login_time` datetime DEFAULT NULL COMMENT '最后登录时间',
  `last_login_ip` varchar(50) DEFAULT NULL COMMENT '最后登录 IP',
  `is_deleted` tinyint DEFAULT '0' COMMENT '是否删除（0 - 未删除，1 - 已删除）',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `id_card` varchar(18) DEFAULT NULL COMMENT '身份证号',
  `last_password_reset_time` datetime DEFAULT NULL COMMENT '最后一次重置密码时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `username` (`username`),
  UNIQUE KEY `idx_sys_users_id_card` (`id_card`)
) ENGINE=InnoDB AUTO_INCREMENT=70 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='系统用户表：存储系统用户基础信息（用户名、密码、状态等），对应用户管理模块核心数据';

-- ----------------------------
-- Records of sys_users
-- ----------------------------
BEGIN;
COMMIT;

